'use client';

import { useState, useMemo } from 'react';
import { PERIODIC_TABLE_DATA, ElementData } from '@/data/periodicTableData';
import { Search, Info, Beaker, Thermometer, Box, Layers, Atom, Zap } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const CATEGORY_COLORS: Record<string, string> = {
    "alkali metal": "#ff3838",
    "alkaline earth metal": "#ffb8b8",
    "transition metal": "#c56cf0",
    "post-transition metal": "#17c0eb",
    "metalloid": "#32ff7e",
    "diatomic nonmetal": "#3ae374",
    "polyatomic nonmetal": "#67e6dc",
    "noble gas": "#7efff5",
    "lanthanide": "#ff9f1a",
    "actinide": "#ffaf40",
    "unknown": "#4b4b4b"
};

const CATEGORY_LABELS: Record<string, string> = {
    "alkali metal": "Alkali Metal",
    "alkaline earth metal": "Alkaline Earth",
    "transition metal": "Transition Metal",
    "post-transition metal": "Post-Transition",
    "metalloid": "Metalloid",
    "diatomic nonmetal": "Nonmetal",
    "polyatomic nonmetal": "Nonmetal",
    "noble gas": "Noble Gas",
    "lanthanide": "Lanthanide",
    "actinide": "Actinide",
    "unknown": "Unknown"
};

export default function PeriodicTableModule({ lang, dict }: { lang: string, dict: any }) {
    const [selected, setSelected] = useState<ElementData | null>(null);
    const [filter, setFilter] = useState('');
    const [hoveredCategory, setHoveredCategory] = useState<string | null>(null);

    const filteredElements = useMemo(() => {
        if (!filter) return PERIODIC_TABLE_DATA;
        const q = filter.toLowerCase();
        return PERIODIC_TABLE_DATA.filter(e =>
            e.name.toLowerCase().includes(q) ||
            e.symbol.toLowerCase().includes(q) ||
            e.number.toString() === q
        );
    }, [filter]);

    // Grid placement logic
    const getGridPos = (el: ElementData) => {
        if (el.number >= 57 && el.number <= 71) return { row: 9, col: el.number - 57 + 3 };
        if (el.number >= 89 && el.number <= 103) return { row: 10, col: el.number - 89 + 3 };
        return { row: el.period, col: el.group };
    };

    const isDimmed = (el: ElementData) => {
        if (hoveredCategory && el.category !== hoveredCategory) return true;
        if (filter && !filteredElements.includes(el)) return true;
        return false;
    };

    return (
        <div className="flex flex-col h-full bg-[#05070a] text-slate-200 overflow-hidden font-sans select-none">
            {/* TOOLBAR */}
            <div className="flex items-center gap-4 px-6 py-4 border-b border-white/5 bg-[#0a0e14]/80 backdrop-blur-xl z-20">
                <div className="relative flex-1 max-w-md group">
                    <div className="absolute -inset-0.5 bg-gradient-to-r from-cyan-500/20 to-purple-500/20 rounded-xl blur opacity-0 group-hover:opacity-100 transition duration-500"></div>
                    <div className="relative flex items-center bg-[#0d131a] border border-white/10 rounded-xl overflow-hidden shadow-inner">
                        <Search className="ml-3 text-cyan-500/50" size={16} />
                        <input
                            type="text"
                            placeholder="Type an element name, symbol, or atomic number..."
                            value={filter}
                            onChange={e => setFilter(e.target.value)}
                            className="w-full bg-transparent px-3 py-2 text-sm text-cyan-50 placeholder-cyan-500/30 focus:outline-none font-mono"
                        />
                    </div>
                </div>

                {/* Legend */}
                <div className="flex flex-wrap gap-2 text-[9px] items-center justify-end flex-1 max-w-[60%]">
                    {Object.entries(CATEGORY_LABELS).map(([key, label]) => {
                        const color = CATEGORY_COLORS[key];
                        return (
                            <div
                                key={key}
                                onMouseEnter={() => setHoveredCategory(key)}
                                onMouseLeave={() => setHoveredCategory(null)}
                                className="flex items-center gap-1.5 px-2.5 py-1 rounded-full cursor-pointer transition-all duration-300 border border-white/5"
                                style={{
                                    backgroundColor: hoveredCategory === key ? `${color}20` : '#ffffff05',
                                    borderColor: hoveredCategory === key ? `${color}40` : 'transparent',
                                    opacity: hoveredCategory && hoveredCategory !== key ? 0.3 : 1,
                                    boxShadow: hoveredCategory === key ? `0 0 10px ${color}20` : 'none'
                                }}
                            >
                                <div className="w-2 h-2 rounded-full shadow-[0_0_5px_currentColor]" style={{ backgroundColor: color, color }} />
                                <span className="uppercase font-bold tracking-widest text-slate-400" style={{ color: hoveredCategory === key ? color : undefined }}>{label}</span>
                            </div>
                        );
                    })}
                </div>
            </div>

            <div className="flex flex-1 overflow-hidden relative">
                {/* Background Grid Pattern */}
                <div className="absolute inset-0 pointer-events-none opacity-[0.03]" style={{ backgroundImage: 'linear-gradient(#ffffff 1px, transparent 1px), linear-gradient(90deg, #ffffff 1px, transparent 1px)', backgroundSize: '40px 40px' }}></div>

                {/* MAIN TABLE AREA */}
                <div className="flex-1 overflow-auto p-8 flex items-center justify-center relative custom-scrollbar z-10">
                    <div
                        className="grid gap-1.5 relative"
                        style={{
                            gridTemplateColumns: 'repeat(18, minmax(40px, 1fr))',
                            gridTemplateRows: 'repeat(10, minmax(40px, 1fr))',
                            maxWidth: '1200px',
                            width: '100%',
                            aspectRatio: '18/10'
                        }}
                    >
                        {PERIODIC_TABLE_DATA.map(el => {
                            const pos = getGridPos(el);
                            const isActive = selected?.number === el.number;
                            const dimmed = isDimmed(el);
                            const color = CATEGORY_COLORS[el.category];

                            return (
                                <motion.button
                                    key={el.number}
                                    onClick={() => setSelected(el)}
                                    layoutId={`el-${el.number}`}
                                    className={`relative flex flex-col items-center justify-center transition-all duration-300 border backdrop-blur-sm
                                        ${isActive ? 'z-30 rounded-lg scale-125 shadow-2xl' : 'rounded-md hover:scale-110 hover:z-20 hover:rounded-lg'}`}
                                    style={{
                                        gridColumn: pos.col,
                                        gridRow: pos.row,
                                        backgroundColor: isActive ? `${color}dd` : (dimmed ? '#ffffff02' : `${color}15`),
                                        borderColor: isActive ? '#ffffff' : (dimmed ? '#ffffff05' : `${color}40`),
                                        boxShadow: isActive ? `0 0 30px ${color}80, inset 0 0 10px ${color}` : (dimmed ? 'none' : `inherit`),
                                        opacity: dimmed ? 0.3 : 1,
                                        filter: dimmed ? 'grayscale(100%)' : 'none',
                                    }}
                                >
                                    <span className={`text-[9px] absolute top-0.5 left-1 font-mono font-bold ${isActive ? 'text-black/60' : 'text-white/40'}`}>
                                        {el.number}
                                    </span>
                                    <span className={`text-sm font-black tracking-tighter ${isActive ? 'text-white' : 'text-slate-200'}`} style={{ textShadow: isActive ? '0 2px 4px rgba(0,0,0,0.5)' : 'none' }}>
                                        {el.symbol}
                                    </span>
                                    <span className={`text-[7px] truncate max-w-[90%] font-bold uppercase ${isActive ? 'text-black/80' : 'text-white/40'}`}>
                                        {el.name}
                                    </span>
                                </motion.button>
                            );
                        })}

                        {/* Spacers for Period 6/7 */}
                        <div className="flex items-center justify-center text-[8px] font-mono tracking-widest text-slate-600 uppercase" style={{ gridColumn: 3, gridRow: 6 }}>57-71</div>
                        <div className="flex items-center justify-center text-[8px] font-mono tracking-widest text-slate-600 uppercase" style={{ gridColumn: 3, gridRow: 7 }}>89-103</div>
                    </div>
                </div>

                {/* DETAILS SIDEBAR */}
                <AnimatePresence>
                    {selected && (
                        <motion.div
                            initial={{ x: '100%', opacity: 0 }}
                            animate={{ x: 0, opacity: 1 }}
                            exit={{ x: '100%', opacity: 0 }}
                            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                            className="w-[420px] bg-[#0a0e14]/90 backdrop-blur-2xl border-l border-white/5 overflow-y-auto custom-scrollbar relative z-30 shadow-[-10px_0_30px_rgba(0,0,0,0.5)]"
                        >
                            {/* Accent Top Line */}
                            <div className="h-1 w-full" style={{ backgroundColor: CATEGORY_COLORS[selected.category] }}></div>

                            <div className="p-8">
                                {/* Close button */}
                                <button onClick={() => setSelected(null)} className="absolute top-4 right-4 text-white/30 hover:text-white transition-colors">
                                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
                                </button>

                                {/* Big Display */}
                                <div className="flex flex-col items-center mb-8 relative">
                                    <div className="absolute inset-0 blur-[60px] opacity-20" style={{ backgroundColor: CATEGORY_COLORS[selected.category] }}></div>
                                    <motion.div layoutId={`el-${selected.number}`} className="w-32 h-32 rounded-2xl flex flex-col items-center justify-center mb-6 border-b-2 shadow-2xl relative z-10"
                                        style={{ backgroundColor: CATEGORY_COLORS[selected.category], borderColor: 'rgba(255,255,255,0.4)', color: '#000' }}
                                    >
                                        <div className="text-sm font-mono font-black opacity-60 absolute top-2 left-3">{selected.number}</div>
                                        <div className="text-6xl font-black tracking-tighter" style={{ textShadow: '0 4px 10px rgba(0,0,0,0.2)' }}>{selected.symbol}</div>
                                        <div className="text-xs font-bold opacity-80 absolute bottom-2">{selected.mass.toFixed(3)}</div>
                                    </motion.div>

                                    <h2 className="text-4xl font-black text-white mb-2 tracking-tight">{selected.name}</h2>

                                    <div className="px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[2px] border mb-6"
                                        style={{ backgroundColor: `${CATEGORY_COLORS[selected.category]}15`, color: CATEGORY_COLORS[selected.category], borderColor: `${CATEGORY_COLORS[selected.category]}40` }}
                                    >
                                        {selected.category}
                                    </div>

                                    <p className="text-sm text-slate-300 text-center leading-relaxed font-medium">
                                        {selected.summary}
                                    </p>
                                </div>

                                {/* Atomic Structure (Bohr) */}
                                <div className="mb-6 p-5 rounded-2xl border border-white/5 bg-black/40 relative overflow-hidden group">
                                    <div className="absolute inset-0 bg-gradient-to-b from-white/[0.02] to-transparent pointer-events-none"></div>
                                    <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 mb-6">
                                        <Atom size={14} className="text-cyan-500" /> Atomic Structure
                                    </h3>
                                    <div className="flex justify-center my-6">
                                        <BohrModel element={selected} color={CATEGORY_COLORS[selected.category]} />
                                    </div>
                                    <div className="mt-4 p-3 bg-[#05070a] rounded-xl border border-white/5 font-mono text-xs text-center text-cyan-200">
                                        {selected.electron_configuration}
                                    </div>
                                </div>

                                {/* Properties Grid */}
                                <div className="grid grid-cols-2 gap-3 mb-6">
                                    <PropCard icon={<Thermometer />} label="Melting Point" value={selected.melt ? `${selected.melt} K` : 'N/A'} sub={selected.melt ? `${(selected.melt - 273.15).toFixed(1)}°C` : ''} color="#ff7675" />
                                    <PropCard icon={<Thermometer />} label="Boiling Point" value={selected.boil ? `${selected.boil} K` : 'N/A'} sub={selected.boil ? `${(selected.boil - 273.15).toFixed(1)}°C` : ''} color="#fdcb6e" />
                                    <PropCard icon={<Box />} label="Density" value={selected.density ? `${selected.density} g/cm³` : 'N/A'} color="#74b9ff" />
                                    <PropCard icon={<Layers />} label="Position" value={`Grp ${selected.group} / Per ${selected.period}`} color="#a29bfe" />
                                </div>

                                {/* Discovered By */}
                                <div className="p-4 rounded-xl border border-white/5 bg-white/[0.02] flex items-center justify-between">
                                    <div className="flex items-center gap-3">
                                        <div className="w-8 h-8 rounded-full bg-cyan-500/10 flex items-center justify-center">
                                            <Search size={14} className="text-cyan-400" />
                                        </div>
                                        <span className="text-[10px] font-bold uppercase tracking-widest text-slate-500">Discovered</span>
                                    </div>
                                    <div className="text-sm font-bold text-white text-right max-w-[180px] truncate">
                                        {selected.discovered_by || 'Unknown'}
                                    </div>
                                </div>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>
        </div>
    );
}

function PropCard({ icon, label, value, sub, color }: { icon: any, label: string, value: string, sub?: string, color: string }) {
    return (
        <div className="p-3 bg-white/[0.02] border border-white/5 rounded-xl flex flex-col items-center justify-center text-center relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-2 opacity-20 group-hover:opacity-40 transition-opacity" style={{ color }}>
                <div className="w-4 h-4">{icon}</div>
            </div>
            <div className="text-[9px] font-bold uppercase tracking-widest text-slate-500 mb-1 z-10">{label}</div>
            <div className="text-sm font-black text-white font-mono z-10">{value}</div>
            {sub && <div className="text-[10px] text-slate-400 font-mono mt-0.5 z-10">{sub}</div>}
        </div>
    );
}

// Ultra-premium Schematic Bohr Model with smooth orbits and glowing electrons
function BohrModel({ element, color }: { element: ElementData, color: string }) {
    const shells = element.period;
    const baseRadius = 25;
    const spacing = 18;
    const svgSize = (baseRadius + (shells * spacing)) * 2 + 20;
    const center = svgSize / 2;

    const electronCounts = getElectronCounts(element.number);

    return (
        <svg width={svgSize} height={svgSize} viewBox={`0 0 ${svgSize} ${svgSize}`} className="overflow-visible">
            {/* Core Glow */}
            <defs>
                <radialGradient id={`glow-${element.number}`} cx="50%" cy="50%" r="50%">
                    <stop offset="0%" stopColor={color} stopOpacity="0.5" />
                    <stop offset="100%" stopColor={color} stopOpacity="0" />
                </radialGradient>
            </defs>
            <circle cx={center} cy={center} r={20} fill={`url(#glow-${element.number})`} className="animate-pulse" />

            {/* Nucleus */}
            <circle cx={center} cy={center} r={12} fill={color} stroke="rgba(255,255,255,0.5)" strokeWidth="2" />
            <text x={center} y={center} dy=".3em" textAnchor="middle" fontSize="10" fontFamily="monospace" fontWeight="900" fill="#000">{element.symbol}</text>

            <g className="animate-spin-slow" style={{ animationDuration: '40s', transformOrigin: `${center}px ${center}px` }}>
                {electronCounts.map((count, i) => {
                    const r = baseRadius + (i * spacing);
                    return (
                        <g key={i}>
                            {/* Orbit path */}
                            <circle cx={center} cy={center} r={r} fill="none" stroke={color} strokeOpacity="0.2" strokeWidth="1" strokeDasharray="4 2" />

                            {/* Electrons */}
                            <g className="animate-spin-slow" style={{ animationDuration: `${20 + i * 10}s`, transformOrigin: `${center}px ${center}px`, animationDirection: i % 2 === 0 ? 'normal' : 'reverse' }}>
                                {Array.from({ length: count }).map((_, j) => {
                                    const angle = (j / count) * Math.PI * 2;
                                    const x = center + r * Math.cos(angle);
                                    const y = center + r * Math.sin(angle);
                                    return (
                                        <g key={j}>
                                            <circle cx={x} cy={y} r={4} fill={color} opacity="0.3" className="animate-ping" />
                                            <circle cx={x} cy={y} r={2.5} fill="#fff" stroke={color} strokeWidth="1" />
                                        </g>
                                    );
                                })}
                            </g>
                        </g>
                    )
                })}
            </g>
        </svg>
    )
}

function getElectronCounts(atomicNumber: number): number[] {
    let remaining = atomicNumber;
    const shells = [];
    let n = 1;
    while (remaining > 0) {
        const capacity = 2 * n * n;
        const take = Math.min(remaining, capacity);
        shells.push(take);
        remaining -= take;
        n++;
        if (n > 7) break;
    }
    // Limit outer shell visual sizes so it doesn't get ridiculously crowded on screen
    return shells.map(c => Math.min(c, 32));
}
